   129→////////////////////////////////////////////////////////////////////////////////
   130→// nsObserverService Implementation
   131→
   132→NS_IMPL_ISUPPORTS(nsObserverService, nsIObserverService, nsObserverService,
   133→                  nsIMemoryReporter)
   134→
   135→nsObserverService::nsObserverService() : mShuttingDown(false) {}
   136→
   137→nsObserverService::~nsObserverService(void) { Shutdown(); }
   138→
   139→void nsObserverService::RegisterReporter() { RegisterWeakMemoryReporter(this); }
   140→
   141→void nsObserverService::Shutdown() {
   142→  if (mShuttingDown) {
   143→    return;
   144→  }
   145→
   146→  mShuttingDown = true;
   147→  UnregisterWeakMemoryReporter(this);
   148→  mObserverTopicTable.Clear();
   149→}
   150→
   151→nsresult nsObserverService::Create(const nsIID& aIID, void** aInstancePtr) {
   152→  LOG(("nsObserverService::Create()"));
   153→
   154→  RefPtr<nsObserverService> os = new nsObserverService();
   155→
   156→  // The memory reporter can not be immediately registered here because
   157→  // the nsMemoryReporterManager may attempt to get the nsObserverService
   158→  // during initialization, causing a recursive GetService.
   159→  NS_DispatchToCurrentThread(
   160→      NewRunnableMethod("nsObserverService::RegisterReporter", os,
   161→                        &nsObserverService::RegisterReporter));
   162→
   163→  return os->QueryInterface(aIID, aInstancePtr);
   164→}
   165→
   166→nsresult nsObserverService::EnsureValidCall() const {
   167→  if (!NS_IsMainThread()) {
   168→    MOZ_CRASH("Using observer service off the main thread!");
   169→    return NS_ERROR_UNEXPECTED;
   170→  }
   171→
   172→  if (mShuttingDown) {
   173→    NS_ERROR("Using observer service after XPCOM shutdown!");
   174→    return NS_ERROR_ILLEGAL_DURING_SHUTDOWN;
   175→  }
   176→
   177→  return NS_OK;
   178→}
   179→
   180→nsresult nsObserverService::FilterHttpOnTopics(const char* aTopic) {
   181→  // Specifically allow some http-on-* observer notifications in the child
   182→  // process.
   183→  if (mozilla::net::IsNeckoChild() && !strncmp(aTopic, "http-on-", 8) &&
   184→      strcmp(aTopic, "http-on-before-stop-request") &&
   185→      strcmp(aTopic, "http-on-failed-opening-request") &&
   186→      strcmp(aTopic, "http-on-resource-cache-response") &&
   187→      strcmp(aTopic, "http-on-opening-request") &&
   188→      strcmp(aTopic, "http-on-stop-request")) {
   189→    nsCOMPtr<nsIConsoleService> console(
   190→        do_GetService(NS_CONSOLESERVICE_CONTRACTID));
   191→    nsCOMPtr<nsIScriptError> error(
   192→        do_CreateInstance(NS_SCRIPTERROR_CONTRACTID));
   193→    error->Init(u"http-on-* observers only work in the parent process"_ns,
   194→                ""_ns, 0, 0, nsIScriptError::warningFlag,
   195→                "chrome javascript"_ns, false /* from private window */,
   196→                true /* from chrome context */);
   197→    console->LogMessage(error);
   198→
   199→    return NS_ERROR_NOT_IMPLEMENTED;
   200→  }
   201→
   202→  return NS_OK;
   203→}
   204→
   205→NS_IMETHODIMP
   206→nsObserverService::AddObserver(nsIObserver* aObserver, const char* aTopic,
   207→                               bool aOwnsWeak) {
   208→  LOG(("nsObserverService::AddObserver(%p: %s, %s)", (void*)aObserver, aTopic,
   209→       aOwnsWeak ? "weak" : "strong"));
   210→
   211→  MOZ_TRY(EnsureValidCall());
   212→  if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
   213→    return NS_ERROR_INVALID_ARG;
   214→  }
   215→
   216→  MOZ_TRY(FilterHttpOnTopics(aTopic));
   217→
   218→  nsObserverList* observerList = mObserverTopicTable.PutEntry(aTopic);
   219→  if (!observerList) {
   220→    return NS_ERROR_OUT_OF_MEMORY;
   221→  }
   222→
   223→  return observerList->AddObserver(aObserver, aOwnsWeak);
   224→}
   225→
   226→NS_IMETHODIMP
   227→nsObserverService::RemoveObserver(nsIObserver* aObserver, const char* aTopic) {
   228→  LOG(("nsObserverService::RemoveObserver(%p: %s)", (void*)aObserver, aTopic));
   229→
   230→  if (mShuttingDown) {
   231→    // The service is shutting down. Let's ignore this call.
   232→    return NS_OK;
   233→  }
   234→
   235→  MOZ_TRY(EnsureValidCall());
   236→  if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
   237→    return NS_ERROR_INVALID_ARG;
   238→  }
   239→
   240→  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
   241→  if (!observerList) {
   242→    return NS_ERROR_FAILURE;
   243→  }
   244→
   245→  return observerList->RemoveObserver(aObserver);
   246→}
   247→
   248→NS_IMETHODIMP
   249→nsObserverService::EnumerateObservers(const char* aTopic,
   250→                                      nsISimpleEnumerator** anEnumerator) {
   251→  LOG(("nsObserverService::EnumerateObservers(%s)", aTopic));
   252→
   253→  MOZ_TRY(EnsureValidCall());
   254→  if (NS_WARN_IF(!anEnumerator) || NS_WARN_IF(!aTopic)) {
   255→    return NS_ERROR_INVALID_ARG;
   256→  }
   257→
   258→  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
   259→  if (!observerList) {
   260→    return NS_NewEmptyEnumerator(anEnumerator);
   261→  }
   262→
   263→  observerList->GetObserverList(anEnumerator);
   264→  return NS_OK;
   265→}
   266→
   267→// Enumerate observers of aTopic and call Observe on each.
   268→NS_IMETHODIMP nsObserverService::NotifyObservers(nsISupports* aSubject,
   269→                                                 const char* aTopic,
   270→                                                 const char16_t* aSomeData) {
   271→  LOG(("nsObserverService::NotifyObservers(%s)", aTopic));
   272→
   273→  MOZ_TRY(EnsureValidCall());
   274→  if (NS_WARN_IF(!aTopic)) {
   275→    return NS_ERROR_INVALID_ARG;
   276→  }
   277→
   278→  MOZ_ASSERT(AppShutdown::IsNoOrLegalShutdownTopic(aTopic));
   279→
   280→  AUTO_PROFILER_MARKER_TEXT("NotifyObservers", OTHER, MarkerStack::Capture(),
   281→                            nsDependentCString(aTopic));
   282→  AUTO_PROFILER_LABEL_DYNAMIC_CSTR_NONSENSITIVE(
   283→      "nsObserverService::NotifyObservers", OTHER, aTopic);
   284→
   285→  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
   286→  if (observerList) {
   287→    observerList->NotifyObservers(aSubject, aTopic, aSomeData);
   288→  }
   289→
   290→  return NS_OK;
   291→}
   292→
   293→NS_IMETHODIMP
   294→nsObserverService::UnmarkGrayStrongObservers() {
   295→  MOZ_TRY(EnsureValidCall());
   296→
   297→  nsCOMArray<nsIObserver> strongObservers;
   298→  for (auto iter = mObserverTopicTable.Iter(); !iter.Done(); iter.Next()) {
   299→    nsObserverList* aObserverList = iter.Get();
   300→    if (aObserverList) {
   301→      aObserverList->AppendStrongObservers(strongObservers);
   302→    }
   303→  }
   304→
   305→  for (uint32_t i = 0; i < strongObservers.Length(); ++i) {
   306→    xpc_TryUnmarkWrappedGrayObject(strongObservers[i]);
   307→  }
   308→
   309→  return NS_OK;
   310→}
   311→
   312→bool nsObserverService::HasObservers(const char* aTopic) {
   313→  return mObserverTopicTable.Contains(aTopic);
   314→}
