    14→#include "nsObserverService.h"
    15→#include "nsObserverList.h"
    16→#include "nsServiceManagerUtils.h"
    17→#include "nsThreadUtils.h"
    18→#include "nsEnumeratorUtils.h"
    19→#include "xpcpublic.h"
    20→#include "mozilla/AppShutdown.h"
    21→#include "mozilla/net/NeckoCommon.h"
    22→#include "mozilla/ProfilerLabels.h"
    23→#include "mozilla/ProfilerMarkers.h"
    24→#include "mozilla/TimeStamp.h"
    25→#include "mozilla/Try.h"
    26→#include "nsString.h"
    27→
    28→// Log module for nsObserverService logging...
    29→//
    30→// To enable logging (see prlog.h for full details):
    31→//
    32→//    set MOZ_LOG=ObserverService:5
    33→//    set MOZ_LOG_FILE=service.log
    34→//
    35→// This enables LogLevel::Debug level information and places all output in
    36→// the file service.log.
    37→static mozilla::LazyLogModule sObserverServiceLog("ObserverService");
    38→#define LOG(x) MOZ_LOG(sObserverServiceLog, mozilla::LogLevel::Debug, x)
    39→
    40→using namespace mozilla;
    41→
    42→NS_IMETHODIMP
    43→nsObserverService::CollectReports(nsIHandleReportCallback* aHandleReport,
    44→                                  nsISupports* aData, bool aAnonymize) {
    45→  struct SuspectObserver {
    46→    SuspectObserver(const char* aTopic, size_t aReferentCount)
    47→        : mTopic(aTopic), mReferentCount(aReferentCount) {}
    48→    const char* mTopic;
    49→    size_t mReferentCount;
    50→  };
    51→
    52→  size_t totalNumStrong = 0;
    53→  size_t totalNumWeakAlive = 0;
    54→  size_t totalNumWeakDead = 0;
    55→  nsTArray<SuspectObserver> suspectObservers;
    56→
    57→  for (auto iter = mObserverTopicTable.Iter(); !iter.Done(); iter.Next()) {
    58→    nsObserverList* observerList = iter.Get();
    59→    if (!observerList) {
    60→      continue;
    61→    }
    62→
    63→    size_t topicNumStrong = 0;
    64→    size_t topicNumWeakAlive = 0;
    65→    size_t topicNumWeakDead = 0;
    66→
    67→    nsMaybeWeakPtrArray<nsIObserver>& observers = observerList->mObservers;
    68→    for (uint32_t i = 0; i < observers.Length(); i++) {
    69→      if (observers[i].IsWeak()) {
    70→        nsCOMPtr<nsIObserver> ref = observers[i].GetValue();
    71→        if (ref) {
    72→          topicNumWeakAlive++;
    73→        } else {
    74→          topicNumWeakDead++;
    75→        }
    76→      } else {
    77→        topicNumStrong++;
    78→      }
    79→    }
    80→
    81→    totalNumStrong += topicNumStrong;
    82→    totalNumWeakAlive += topicNumWeakAlive;
    83→    totalNumWeakDead += topicNumWeakDead;
    84→
    85→    // Keep track of topics that have a suspiciously large number
    86→    // of referents (symptom of leaks).
    87→    size_t topicTotal = topicNumStrong + topicNumWeakAlive + topicNumWeakDead;
    88→    if (topicTotal > kSuspectReferentCount) {
    89→      SuspectObserver suspect(observerList->GetKey(), topicTotal);
    90→      suspectObservers.AppendElement(suspect);
    91→    }
    92→  }
    93→
    94→  // These aren't privacy-sensitive and so don't need anonymizing.
    95→  for (uint32_t i = 0; i < suspectObservers.Length(); i++) {
    96→    SuspectObserver& suspect = suspectObservers[i];
    97→    nsPrintfCString suspectPath("observer-service-suspect/referent(topic=%s)",
    98→                                suspect.mTopic);
    99→    aHandleReport->Callback(
   100→        /* process */ ""_ns, suspectPath, KIND_OTHER, UNITS_COUNT,
   101→        suspect.mReferentCount,
   102→        nsLiteralCString("A topic with a suspiciously large number of "
   103→                         "referents.  This may be symptomatic of a leak "
   104→                         "if the number of referents is high with "
   105→                         "respect to the number of windows."),
   106→        aData);
   107→  }
   108→
   109→  MOZ_COLLECT_REPORT(
   110→      "observer-service/referent/strong", KIND_OTHER, UNITS_COUNT,
   111→      totalNumStrong,
   112→      "The number of strong references held by the observer service.");
   113→
   114→  MOZ_COLLECT_REPORT(
   115→      "observer-service/referent/weak/alive", KIND_OTHER, UNITS_COUNT,
   116→      totalNumWeakAlive,
   117→      "The number of weak references held by the observer service that are "
   118→      "still alive.");
   119→
   120→  MOZ_COLLECT_REPORT(
   121→      "observer-service/referent/weak/dead", KIND_OTHER, UNITS_COUNT,
   122→      totalNumWeakDead,
   123→      "The number of weak references held by the observer service that are "
   124→      "dead.");
   125→
   126→  return NS_OK;
   127→}
   128→
   129→////////////////////////////////////////////////////////////////////////////////
   130→// nsObserverService Implementation
   131→
   132→NS_IMPL_ISUPPORTS(nsObserverService, nsIObserverService, nsObserverService,
   133→                  nsIMemoryReporter)
   134→
   135→nsObserverService::nsObserverService() : mShuttingDown(false) {}
   136→
   137→nsObserverService::~nsObserverService(void) { Shutdown(); }
   138→
   139→void nsObserverService::RegisterReporter() { RegisterWeakMemoryReporter(this); }
   140→
   141→void nsObserverService::Shutdown() {
   142→  if (mShuttingDown) {
   143→    return;
   144→  }
   145→
   146→  mShuttingDown = true;
   147→  UnregisterWeakMemoryReporter(this);
   148→  mObserverTopicTable.Clear();
   149→}
   150→
   151→nsresult nsObserverService::Create(const nsIID& aIID, void** aInstancePtr) {
   152→  LOG(("nsObserverService::Create()"));
   153→
   154→  RefPtr<nsObserverService> os = new nsObserverService();
   155→
   156→  // The memory reporter can not be immediately registered here because
   157→  // the nsMemoryReporterManager may attempt to get the nsObserverService
   158→  // during initialization, causing a recursive GetService.
   159→  NS_DispatchToCurrentThread(
   160→      NewRunnableMethod("nsObserverService::RegisterReporter", os,
   161→                        &nsObserverService::RegisterReporter));
   162→
   163→  return os->QueryInterface(aIID, aInstancePtr);
   164→}
   165→
   166→nsresult nsObserverService::EnsureValidCall() const {
   167→  if (!NS_IsMainThread()) {
   168→    MOZ_CRASH("Using observer service off the main thread!");
   169→    return NS_ERROR_UNEXPECTED;
   170→  }
   171→
   172→  if (mShuttingDown) {
   173→    NS_ERROR("Using observer service after XPCOM shutdown!");
   174→    return NS_ERROR_ILLEGAL_DURING_SHUTDOWN;
   175→  }
   176→
   177→  return NS_OK;
   178→}
   179→
   180→nsresult nsObserverService::FilterHttpOnTopics(const char* aTopic) {
   181→  // Specifically allow some http-on-* observer notifications in the child
   182→  // process.
   183→  if (mozilla::net::IsNeckoChild() && !strncmp(aTopic, "http-on-", 8) &&
   184→      strcmp(aTopic, "http-on-before-stop-request") &&
   185→      strcmp(aTopic, "http-on-failed-opening-request") &&
   186→      strcmp(aTopic, "http-on-resource-cache-response") &&
   187→      strcmp(aTopic, "http-on-opening-request") &&
   188→      strcmp(aTopic, "http-on-stop-request")) {
   189→    nsCOMPtr<nsIConsoleService> console(
   190→        do_GetService(NS_CONSOLESERVICE_CONTRACTID));
   191→    nsCOMPtr<nsIScriptError> error(
   192→        do_CreateInstance(NS_SCRIPTERROR_CONTRACTID));
   193→    error->Init(u"http-on-* observers only work in the parent process"_ns,
   194→                ""_ns, 0, 0, nsIScriptError::warningFlag,
   195→                "chrome javascript"_ns, false /* from private window */,
   196→                true /* from chrome context */);
   197→    console->LogMessage(error);
   198→
   199→    return NS_ERROR_NOT_IMPLEMENTED;
   200→  }
   201→
   202→  return NS_OK;
   203→}
   204→
   205→NS_IMETHODIMP
   206→nsObserverService::AddObserver(nsIObserver* aObserver, const char* aTopic,
   207→                               bool aOwnsWeak) {
   208→  LOG(("nsObserverService::AddObserver(%p: %s, %s)", (void*)aObserver, aTopic,
   209→       aOwnsWeak ? "weak" : "strong"));
   210→
   211→  MOZ_TRY(EnsureValidCall());
   212→  if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
   213→    return NS_ERROR_INVALID_ARG;
   214→  }
   215→
   216→  MOZ_TRY(FilterHttpOnTopics(aTopic));
   217→
   218→  nsObserverList* observerList = mObserverTopicTable.PutEntry(aTopic);
   219→  if (!observerList) {
   220→    return NS_ERROR_OUT_OF_MEMORY;
   221→  }
   222→
   223→  return observerList->AddObserver(aObserver, aOwnsWeak);
   224→}
   225→
   226→NS_IMETHODIMP
   227→nsObserverService::RemoveObserver(nsIObserver* aObserver, const char* aTopic) {
   228→  LOG(("nsObserverService::RemoveObserver(%p: %s)", (void*)aObserver, aTopic));
   229→
   230→  if (mShuttingDown) {
   231→    // The service is shutting down. Let's ignore this call.
   232→    return NS_OK;
   233→  }
   234→
   235→  MOZ_TRY(EnsureValidCall());
   236→  if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
   237→    return NS_ERROR_INVALID_ARG;
   238→  }
   239→
   240→  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
   241→  if (!observerList) {
   242→    return NS_ERROR_FAILURE;
   243→  }
   244→
   245→  return observerList->RemoveObserver(aObserver);
   246→}
   247→
   248→NS_IMETHODIMP
   249→nsObserverService::EnumerateObservers(const char* aTopic,
   250→                                      nsISimpleEnumerator** anEnumerator) {
   251→  LOG(("nsObserverService::EnumerateObservers(%s)", aTopic));
   252→
   253→  MOZ_TRY(EnsureValidCall());
   254→  if (NS_WARN_IF(!anEnumerator) || NS_WARN_IF(!aTopic)) {
   255→    return NS_ERROR_INVALID_ARG;
   256→  }
   257→
   258→  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
   259→  if (!observerList) {
   260→    return NS_NewEmptyEnumerator(anEnumerator);
   261→  }
   262→
   263→  observerList->GetObserverList(anEnumerator);
   264→  return NS_OK;
   265→}
   266→
   267→// Enumerate observers of aTopic and call Observe on each.
   268→NS_IMETHODIMP nsObserverService::NotifyObservers(nsISupports* aSubject,
   269→                                                 const char* aTopic,
   270→                                                 const char16_t* aSomeData) {
   271→  LOG(("nsObserverService::NotifyObservers(%s)", aTopic));
   272→
   273→  MOZ_TRY(EnsureValidCall());
   274→  if (NS_WARN_IF(!aTopic)) {
   275→    return NS_ERROR_INVALID_ARG;
   276→  }
   277→
   278→  MOZ_ASSERT(AppShutdown::IsNoOrLegalShutdownTopic(aTopic));
   279→
   280→  AUTO_PROFILER_MARKER_TEXT("NotifyObservers", OTHER, MarkerStack::Capture(),
   281→                            nsDependentCString(aTopic));
   282→  AUTO_PROFILER_LABEL_DYNAMIC_CSTR_NONSENSITIVE(
   283→      "nsObserverService::NotifyObservers", OTHER, aTopic);
   284→
   285→  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
   286→  if (observerList) {
   287→    observerList->NotifyObservers(aSubject, aTopic, aSomeData);
   288→  }
   289→
   290→  return NS_OK;
   291→}
   292→
   293→NS_IMETHODIMP
   294→nsObserverService::UnmarkGrayStrongObservers() {
   295→  MOZ_TRY(EnsureValidCall());
   296→
   297→  nsCOMArray<nsIObserver> strongObservers;
   298→  for (auto iter = mObserverTopicTable.Iter(); !iter.Done(); iter.Next()) {
   299→    nsObserverList* aObserverList = iter.Get();
   300→    if (aObserverList) {
   301→      aObserverList->AppendStrongObservers(strongObservers);
   302→    }
   303→  }
   304→
   305→  for (uint32_t i = 0; i < strongObservers.Length(); ++i) {
   306→    xpc_TryUnmarkWrappedGrayObject(strongObservers[i]);
   307→  }
   308→
   309→  return NS_OK;
   310→}
   311→
   312→bool nsObserverService::HasObservers(const char* aTopic) {
   313→  return mObserverTopicTable.Contains(aTopic);
   314→}
   315→
   316→namespace {
   317→
   318→class NotifyWhenScriptSafeRunnable : public mozilla::Runnable {
   319→ public:
   320→  NotifyWhenScriptSafeRunnable(nsIObserverService* aObs, nsISupports* aSubject,
   321→                               const char* aTopic, const char16_t* aData)
   322→      : mozilla::Runnable("NotifyWhenScriptSafeRunnable"),
   323→        mObs(aObs),
   324→        mSubject(aSubject),
   325→        mTopic(aTopic) {
   326→    if (aData) {
   327→      mData.Assign(aData);
   328→    } else {
   329→      mData.SetIsVoid(true);
   330→    }
   331→  }
   332→
   333→  NS_IMETHOD Run() override {
   334→    const char16_t* data = mData.IsVoid() ? nullptr : mData.get();
   335→    return mObs->NotifyObservers(mSubject, mTopic.get(), data);
   336→  }
   337→
   338→ private:
   339→  nsCOMPtr<nsIObserverService> mObs;
   340→  nsCOMPtr<nsISupports> mSubject;
   341→  nsCString mTopic;
   342→  nsString mData;
   343→};
   344→
   345→}  // namespace
   346→
   347→nsresult nsIObserverService::NotifyWhenScriptSafe(nsISupports* aSubject,
   348→                                                  const char* aTopic,
   349→                                                  const char16_t* aData) {
   350→  if (nsContentUtils::IsSafeToRunScript()) {
   351→    return NotifyObservers(aSubject, aTopic, aData);
   352→  }
   353→
   354→  nsContentUtils::AddScriptRunner(MakeAndAddRef<NotifyWhenScriptSafeRunnable>(
   355→      this, aSubject, aTopic, aData));
   356→  return NS_OK;
   357→}
